// Generated by AI (UnitTest MCP)
use super::{next_non_newline, split_on_comma, supports_javascript};
use crate::ingest::javascript::{is_identifier_shadowed, tokenize, variable_declarator_at, Token};
use crate::ingest::normalize_path;

/// A resolved import destination.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum ImportTarget {
    ArtifactCandidates(Vec<String>),
    Package(String),
}

/// One imported name and the local name used to reference it.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ImportBinding {
    pub imported: String,
    pub local: String,
}

/// An import declaration resolved to a workspace artifact or external package.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Import {
    pub specifier: String,
    pub target: ImportTarget,
    pub bindings: Vec<ImportBinding>,
}

/// Extract supported JavaScript/TypeScript imports without executing code.
pub fn extract(path: &str, content: &str) -> Vec<Import> {
    if !supports_javascript(path) {
        return Vec::new();
    }

    let tokens = tokenize(content);
    let mut imports = Vec::new();
    let mut index = 0;
    while index < tokens.len() {
        if tokens[index].identifier() == Some("import") {
            if let Some(next) = next_non_newline(&tokens, index + 1) {
                if tokens[next].is_punctuation('(') {
                    index += 1;
                    continue;
                }
                if let Some(specifier) = tokens[next].string_literal() {
                    merge_import(&mut imports, build_import(path, specifier, Vec::new()));
                    index = next + 1;
                    continue;
                }
            }
            if let Some((from, specifier_index)) = find_import_from(&tokens, index + 1) {
                if let Some(specifier) = tokens[specifier_index].string_literal() {
                    merge_import(
                        &mut imports,
                        build_import(
                            path,
                            specifier,
                            parse_import_clause(&tokens[index + 1..from]),
                        ),
                    );
                    index = specifier_index + 1;
                    continue;
                }
            }
        } else if tokens[index].identifier() == Some("require")
            && is_bare_identifier(&tokens, index)
            && !is_identifier_shadowed(&tokens, index, "require")
        {
            if let Some(specifier) = require_specifier(&tokens, index) {
                let bindings = require_binding(&tokens, index)
                    .map(parse_require_binding)
                    .unwrap_or_default();
                merge_import(&mut imports, build_import(path, specifier, bindings));
            }
        }
        index += 1;
    }
    imports
}

fn build_import(path: &str, specifier: &str, bindings: Vec<ImportBinding>) -> Import {
    Import {
        specifier: specifier.to_string(),
        target: if specifier.starts_with('.') {
            ImportTarget::ArtifactCandidates(relative_candidates(path, specifier))
        } else {
            ImportTarget::Package(package_name(specifier))
        },
        bindings,
    }
}

fn parse_import_clause(tokens: &[Token]) -> Vec<ImportBinding> {
    let mut bindings = Vec::new();
    let start = tokens.iter().position(|token| token.is_punctuation('{'));
    let end = tokens.iter().rposition(|token| token.is_punctuation('}'));
    if let (Some(start), Some(end)) = (start, end) {
        for item in split_on_comma(&tokens[start + 1..end]) {
            let names: Vec<&str> = item
                .iter()
                .filter_map(Token::identifier)
                .filter(|name| *name != "type")
                .collect();
            if let Some(imported) = names.first() {
                let local = if names.get(1) == Some(&"as") {
                    names.get(2).copied().unwrap_or(imported)
                } else {
                    imported
                };
                bindings.push(ImportBinding {
                    imported: (*imported).to_string(),
                    local: local.to_string(),
                });
            }
        }
    }

    let prefix = tokens
        .iter()
        .take_while(|token| !token.is_punctuation(',') && !token.is_punctuation('{'))
        .filter_map(Token::identifier)
        .find(|name| *name != "type");
    if let Some(prefix) = prefix {
        bindings.push(ImportBinding {
            imported: "default".to_string(),
            local: prefix.to_string(),
        });
    }
    if let Some(star) = tokens.iter().position(|token| token.is_punctuation('*')) {
        if tokens.get(star + 1).and_then(Token::identifier) == Some("as") {
            if let Some(namespace) = tokens.get(star + 2).and_then(Token::identifier) {
                bindings.push(ImportBinding {
                    imported: "*".to_string(),
                    local: namespace.to_string(),
                });
            }
        }
    }
    bindings
}

fn parse_require_binding(tokens: &[Token]) -> Vec<ImportBinding> {
    let start = tokens
        .iter()
        .position(|token| !token.is_newline())
        .unwrap_or(0);
    let end = tokens
        .iter()
        .rposition(|token| !token.is_newline())
        .map(|index| index + 1)
        .unwrap_or(start);
    let tokens = &tokens[start..end];
    if tokens
        .first()
        .is_some_and(|token| token.is_punctuation('{'))
    {
        return split_on_comma(tokens)
            .into_iter()
            .filter_map(|item| {
                let names: Vec<&str> = item.iter().filter_map(Token::identifier).collect();
                let imported = names.first()?;
                let local = names.get(1).copied().unwrap_or(imported);
                Some(ImportBinding {
                    imported: (*imported).to_string(),
                    local: local.to_string(),
                })
            })
            .collect();
    }
    if let Some(binding) = tokens.iter().find_map(Token::identifier) {
        return vec![ImportBinding {
            imported: "default".to_string(),
            local: binding.to_string(),
        }];
    }
    Vec::new()
}

fn find_import_from(tokens: &[Token], start: usize) -> Option<(usize, usize)> {
    for index in start..tokens.len() {
        if tokens[index].is_punctuation(';') {
            return None;
        }
        if tokens[index].identifier() == Some("from") {
            let specifier = next_non_newline(tokens, index + 1)?;
            return tokens[specifier]
                .string_literal()
                .map(|_| (index, specifier));
        }
    }
    None
}

fn require_specifier(tokens: &[Token], require: usize) -> Option<&str> {
    let open = next_non_newline(tokens, require + 1)?;
    let specifier = next_non_newline(tokens, open + 1)?;
    let close = next_non_newline(tokens, specifier + 1)?;
    (tokens[open].is_punctuation('(') && tokens[close].is_punctuation(')'))
        .then(|| tokens[specifier].string_literal())
        .flatten()
}

fn require_binding(tokens: &[Token], require: usize) -> Option<&[Token]> {
    let declaration = (0..require).rev().find(|index| {
        matches!(tokens[*index].identifier(), Some("const" | "let" | "var"))
            && variable_declarator_at(tokens, *index, require).is_some()
    })?;
    let declarator = variable_declarator_at(tokens, declaration, require)?;
    let equals = declarator
        .iter()
        .position(|token| token.is_punctuation('='))?;
    Some(&declarator[..equals])
}

fn relative_candidates(source_path: &str, specifier: &str) -> Vec<String> {
    let source_path = normalize_path(source_path);
    let directory = source_path
        .rsplit_once('/')
        .map(|(dir, _)| dir)
        .unwrap_or("");
    let joined = if directory.is_empty() {
        normalize_path(specifier)
    } else {
        format!("{directory}/{}", normalize_path(specifier))
    };
    let mut parts = Vec::new();
    for part in joined.split('/') {
        match part {
            "" | "." => {}
            ".." => {
                parts.pop();
            }
            _ => parts.push(part),
        }
    }
    let target = parts.join("/");
    let last = parts.last().copied().unwrap_or("");
    let mut candidates = Vec::new();
    if last.contains('.') {
        candidates.push(target.clone());
        if let Some(base) = target.strip_suffix(".js") {
            candidates.push(format!("{base}.ts"));
            candidates.push(format!("{base}.tsx"));
        }
    } else {
        for extension in candidate_extensions(&source_path) {
            candidates.push(format!("{target}.{extension}"));
        }
        for extension in candidate_extensions(&source_path) {
            candidates.push(format!("{target}/index.{extension}"));
        }
    }
    candidates
}

fn package_name(specifier: &str) -> String {
    let mut parts = specifier.split('/');
    let first = parts.next().unwrap_or(specifier);
    if first.starts_with('@') {
        match parts.next() {
            Some(second) => format!("{first}/{second}"),
            None => first.to_string(),
        }
    } else {
        first.to_string()
    }
}

fn merge_import(imports: &mut Vec<Import>, candidate: Import) {
    if let Some(existing) = imports
        .iter_mut()
        .find(|item| item.target == candidate.target)
    {
        for binding in candidate.bindings {
            if !existing.bindings.contains(&binding) {
                existing.bindings.push(binding);
            }
        }
    } else {
        imports.push(candidate);
    }
}

fn candidate_extensions(source_path: &str) -> &'static [&'static str] {
    match source_path.rsplit('.').next() {
        Some("tsx") => &["tsx", "ts", "js", "jsx", "mjs", "cjs"],
        Some("ts") => &["ts", "tsx", "js", "jsx", "mjs", "cjs"],
        Some("jsx") => &["jsx", "js", "tsx", "ts", "mjs", "cjs"],
        Some("mjs") => &["mjs", "js", "cjs", "ts", "tsx", "jsx"],
        Some("cjs") => &["cjs", "js", "mjs", "ts", "tsx", "jsx"],
        _ => &["js", "jsx", "mjs", "cjs", "ts", "tsx"],
    }
}

fn is_bare_identifier(tokens: &[Token], index: usize) -> bool {
    match previous_non_newline(tokens, index) {
        Some(previous) => !tokens[previous].is_punctuation('.'),
        None => true,
    }
}

fn previous_non_newline(tokens: &[Token], index: usize) -> Option<usize> {
    (0..index)
        .rev()
        .find(|previous| !tokens[*previous].is_newline())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn extracts_named_imports_and_resolves_relative_artifact() {
        let imports = extract(
            "src/feature/consumer.ts",
            r#"import { dependency, helper as localHelper } from "../dependency";"#,
        );

        assert_eq!(imports.len(), 1);
        let ImportTarget::ArtifactCandidates(candidates) = &imports[0].target else {
            panic!("expected relative artifact candidates");
        };
        assert_eq!(candidates[0], "src/dependency.ts");
        assert!(imports[0].bindings.contains(&ImportBinding {
            imported: "dependency".to_string(),
            local: "dependency".to_string(),
        }));
        assert!(imports[0].bindings.contains(&ImportBinding {
            imported: "helper".to_string(),
            local: "localHelper".to_string(),
        }));
    }

    #[test]
    fn extracts_scoped_package_root_and_default_binding() {
        let imports = extract("src/view.tsx", r#"import React from "@scope/ui/button";"#);

        assert_eq!(
            imports,
            vec![Import {
                specifier: "@scope/ui/button".to_string(),
                target: ImportTarget::Package("@scope/ui".to_string()),
                bindings: vec![ImportBinding {
                    imported: "default".to_string(),
                    local: "React".to_string(),
                }],
            }]
        );
    }

    #[test]
    fn merges_assigned_and_bare_commonjs_requires() {
        let imports = extract(
            "src/consumer.js",
            "const { readFile: read } = require('node:fs');\nrequire('node:fs');\n",
        );

        assert_eq!(imports.len(), 1);
        assert_eq!(
            imports[0].target,
            ImportTarget::Package("node:fs".to_string())
        );
        assert_eq!(
            imports[0].bindings,
            vec![ImportBinding {
                imported: "readFile".to_string(),
                local: "read".to_string(),
            }]
        );
    }

    #[test]
    fn resolves_directory_import_to_index_with_source_extension() {
        let imports = extract("src/consumer.ts", r#"import "./feature/";"#);

        let ImportTarget::ArtifactCandidates(candidates) = &imports[0].target else {
            panic!("expected relative artifact candidates");
        };
        assert!(candidates.contains(&"src/feature/index.ts".to_string()));
    }

    #[test]
    fn extracts_multiline_named_import() {
        let imports = extract(
            "src/consumer.ts",
            "import {\n  dependency,\n  helper as localHelper,\n} from './dependency';\n",
        );

        assert_eq!(imports.len(), 1);
        assert!(imports[0].bindings.contains(&ImportBinding {
            imported: "dependency".to_string(),
            local: "dependency".to_string(),
        }));
        assert!(imports[0].bindings.contains(&ImportBinding {
            imported: "helper".to_string(),
            local: "localHelper".to_string(),
        }));
    }

    #[test]
    fn ignores_commented_string_member_and_shadowed_require_calls() {
        let source = r#"
// require("commented")
const text = "require('string')";
object.require("member");
function require(value) { return value; }
require("shadowed");
"#;

        assert!(extract("src/consumer.js", source).is_empty());
    }

    #[test]
    fn ignores_require_shadowed_by_later_function_declaration() {
        let source = "require('ghost');\nfunction require(value) { return value; }\n";

        assert!(extract("src/consumer.js", source).is_empty());
    }

    #[test]
    fn nested_require_declaration_does_not_suppress_outer_call() {
        let source =
            "function scoped() { const require = local; require('ghost'); }\nrequire('real');\n";
        let imports = extract("src/consumer.js", source);

        assert_eq!(imports.len(), 1);
        assert_eq!(imports[0].target, ImportTarget::Package("real".to_string()));
    }

    #[test]
    fn named_require_binding_uses_its_own_later_declarator() {
        let imports = extract(
            "src/consumer.js",
            "const first = value,\n { dependency: localDependency } = require('./dependency');\n",
        );

        assert_eq!(imports.len(), 1);
        assert_eq!(
            imports[0].bindings,
            vec![ImportBinding {
                imported: "dependency".to_string(),
                local: "localDependency".to_string(),
            }]
        );
    }

    #[test]
    fn ignores_unsupported_source_extensions() {
        assert!(extract("src/lib.rs", "use crate::dependency;").is_empty());
    }
}
